<svg viewBox="0 0 700 620" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Colapso del Token LAB — Precio, Concentración de Suministro, Calendario de Desbloqueo</text>
  <g font-family="sans-serif">
    <text x="20" y="60" fill="#a1a1aa" font-size="13">1. Precio (8 → 12 de julio)</text>
    <rect x="20" y="75" width="660" height="46" rx="8" fill="#f87171" opacity="0.85"/>
    <text x="350" y="103" fill="#111113" font-size="14" font-weight="700" text-anchor="middle">~$1.20 → menos de $0.55 (caída del 80-97%, ~$5.000M en cap. de mercado borrados)</text>

    <text x="20" y="150" fill="#a1a1aa" font-size="13">2. Estructura de control del suministro (según ZachXBT)</text>
    <rect x="20" y="165" width="627" height="40" rx="8" fill="#dc2626" opacity="0.9"/>
